import React from 'react';
import styled from 'styled-components';
import { motion } from 'framer-motion';

const Section = styled.section`
  padding: 120px 60px;
  background: #FFFDF4;

  @media (max-width: 768px) {
    padding: 80px 30px;
  }
`;

const Container = styled.div`
  max-width: 1000px;
  margin: 0 auto;
`;

const SectionHeader = styled.div`
  text-align: center;
  margin-bottom: 60px;
`;

const Subtitle = styled(motion.p)`
  font-family: 'Montserrat', sans-serif;
  font-size: 0.7rem;
  font-weight: 500;
  letter-spacing: 4px;
  text-transform: uppercase;
  color: #D4AF37;
  margin-bottom: 15px;
`;

const Title = styled(motion.h2)`
  font-family: 'Cormorant Garamond', serif;
  font-size: 3rem;
  font-weight: 300;
  color: #800020;
  letter-spacing: 4px;
  text-transform: uppercase;

  @media (max-width: 768px) {
    font-size: 2rem;
  }
`;

const FormContainer = styled(motion.div)`
  background: #F5F0EB;
  padding: 60px;
  position: relative;

  &:before {
    content: '';
    position: absolute;
    top: 20px;
    left: 20px;
    right: -20px;
    bottom: -20px;
    border: 1px solid #D4AF37;
    z-index: -1;
  }

  @media (max-width: 768px) {
    padding: 40px 30px;
  }
`;

const Form = styled.form`
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 30px;

  @media (max-width: 768px) {
    grid-template-columns: 1fr;
  }
`;

const FormGroup = styled.div`
  &.full-width {
    grid-column: span 2;

    @media (max-width: 768px) {
      grid-column: span 1;
    }
  }
`;

const Label = styled.label`
  display: block;
  font-family: 'Montserrat', sans-serif;
  font-size: 0.7rem;
  font-weight: 500;
  letter-spacing: 2px;
  text-transform: uppercase;
  color: #666;
  margin-bottom: 10px;
`;

const Input = styled.input`
  width: 100%;
  padding: 15px 0;
  background: transparent;
  border: none;
  border-bottom: 1px solid #ccc;
  font-family: 'Cormorant Garamond', serif;
  font-size: 1.1rem;
  color: #1a1a1a;
  transition: border-color 0.3s ease;

  &:focus {
    outline: none;
    border-bottom-color: #800020;
  }

  &::placeholder {
    color: #999;
  }
`;

const TextArea = styled.textarea`
  width: 100%;
  padding: 15px 0;
  background: transparent;
  border: none;
  border-bottom: 1px solid #ccc;
  font-family: 'Cormorant Garamond', serif;
  font-size: 1.1rem;
  color: #1a1a1a;
  resize: vertical;
  min-height: 120px;
  transition: border-color 0.3s ease;

  &:focus {
    outline: none;
    border-bottom-color: #800020;
  }

  &::placeholder {
    color: #999;
  }
`;

const Select = styled.select`
  width: 100%;
  padding: 15px 0;
  background: transparent;
  border: none;
  border-bottom: 1px solid #ccc;
  font-family: 'Cormorant Garamond', serif;
  font-size: 1.1rem;
  color: #1a1a1a;
  cursor: pointer;
  transition: border-color 0.3s ease;

  &:focus {
    outline: none;
    border-bottom-color: #800020;
  }
`;

const SubmitButton = styled(motion.button)`
  grid-column: span 2;
  font-family: 'Montserrat', sans-serif;
  font-size: 0.7rem;
  font-weight: 500;
  letter-spacing: 3px;
  text-transform: uppercase;
  color: #FFFDF4;
  background: #800020;
  padding: 20px 50px;
  border: 1px solid #800020;
  cursor: pointer;
  transition: all 0.4s ease;
  margin-top: 20px;
  justify-self: start;

  &:hover {
    background: transparent;
    color: #800020;
  }

  @media (max-width: 768px) {
    grid-column: span 1;
    width: 100%;
  }
`;

const ContactInfo = styled(motion.div)`
  display: flex;
  justify-content: center;
  gap: 60px;
  margin-top: 80px;

  @media (max-width: 768px) {
    flex-direction: column;
    align-items: center;
    gap: 30px;
    text-align: center;
  }
`;

const InfoItem = styled.div``;

const InfoLabel = styled.span`
  display: block;
  font-family: 'Montserrat', sans-serif;
  font-size: 0.65rem;
  font-weight: 500;
  letter-spacing: 2px;
  text-transform: uppercase;
  color: #D4AF37;
  margin-bottom: 8px;
`;

const InfoValue = styled.span`
  font-family: 'Cormorant Garamond', serif;
  font-size: 1.1rem;
  color: #666;
`;

function Contact() {
  const handleSubmit = (e) => {
    e.preventDefault();
    alert('Thank you for your inquiry. We will be in touch shortly.');
  };

  return (
    <Section id="contact">
      <Container>
        <SectionHeader>
          <Subtitle
            initial={{ opacity: 0, y: 20 }}
            whileInView={{ opacity: 1, y: 0 }}
            viewport={{ once: true }}
            transition={{ duration: 0.6 }}
          >
            Get in Touch
          </Subtitle>
          <Title
            initial={{ opacity: 0, y: 20 }}
            whileInView={{ opacity: 1, y: 0 }}
            viewport={{ once: true }}
            transition={{ duration: 0.6, delay: 0.1 }}
          >
            Contact Us
          </Title>
        </SectionHeader>

        <FormContainer
          initial={{ opacity: 0, y: 50 }}
          whileInView={{ opacity: 1, y: 0 }}
          viewport={{ once: true }}
          transition={{ duration: 0.8 }}
        >
          <Form onSubmit={handleSubmit}>
            <FormGroup>
              <Label>First Name</Label>
              <Input type="text" placeholder="Your first name" required />
            </FormGroup>
            <FormGroup>
              <Label>Last Name</Label>
              <Input type="text" placeholder="Your last name" required />
            </FormGroup>
            <FormGroup>
              <Label>Email</Label>
              <Input type="email" placeholder="your@email.com" required />
            </FormGroup>
            <FormGroup>
              <Label>Interest</Label>
              <Select required>
                <option value="">Select your interest</option>
                <option value="collection">Collection Inquiry</option>
                <option value="custom">Custom Design</option>
                <option value="press">Press & Media</option>
                <option value="partnership">Partnership</option>
                <option value="other">Other</option>
              </Select>
            </FormGroup>
            <FormGroup className="full-width">
              <Label>Message</Label>
              <TextArea placeholder="Tell us about your inquiry..." required />
            </FormGroup>
            <SubmitButton
              type="submit"
              whileHover={{ scale: 1.02 }}
              whileTap={{ scale: 0.98 }}
            >
              Send Message
            </SubmitButton>
          </Form>
        </FormContainer>

        <ContactInfo
          initial={{ opacity: 0, y: 30 }}
          whileInView={{ opacity: 1, y: 0 }}
          viewport={{ once: true }}
          transition={{ duration: 0.6, delay: 0.3 }}
        >
